import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        int[] nums1 = {1, 2, 3, 0, 0, 0};
        new Solution().merge(nums1, 3, new int[]{2, 5, 6}, 3);
        assertArrayEquals(new int[]{1, 2, 2, 3, 5, 6}, nums1);
    }

    @Test
    void nums2AllLarger() {
        int[] nums1 = {1, 2, 3, 0, 0, 0};
        new Solution().merge(nums1, 3, new int[]{4, 5, 6}, 3);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5, 6}, nums1);
    }

    @Test
    void nums2AllSmaller() {
        int[] nums1 = {4, 5, 6, 0, 0, 0};
        new Solution().merge(nums1, 3, new int[]{1, 2, 3}, 3);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5, 6}, nums1);
    }

    @Test
    void nums2Empty() {
        // n = 0: nums1 is already the answer
        int[] nums1 = {1, 2, 3};
        new Solution().merge(nums1, 3, new int[]{}, 0);
        assertArrayEquals(new int[]{1, 2, 3}, nums1);
    }

    @Test
    void nums1Empty() {
        // m = 0: entire result comes from nums2
        int[] nums1 = {0, 0, 0};
        new Solution().merge(nums1, 0, new int[]{1, 2, 3}, 3);
        assertArrayEquals(new int[]{1, 2, 3}, nums1);
    }

    @Test
    void singleEach() {
        int[] nums1 = {2, 0};
        new Solution().merge(nums1, 1, new int[]{1}, 1);
        assertArrayEquals(new int[]{1, 2}, nums1);
    }

    @Test
    void withDuplicatesAcrossArrays() {
        // adversarial: duplicate values that span both arrays
        int[] nums1 = {1, 3, 5, 0, 0, 0, 0};
        new Solution().merge(nums1, 3, new int[]{1, 3, 5, 7}, 4);
        assertArrayEquals(new int[]{1, 1, 3, 3, 5, 5, 7}, nums1);
    }
}
